    for(const layer of [this.focusGlowLayer,this.focusLeaderLayer,this.focusNodeLayer,this.focusLabelLayer])layer.removeChildren().forEach(child=>child.destroy());
    this.glowLayer.removeChildren().forEach((child) => child.destroy());
    this.leaderLayer.removeChildren().forEach((child) => child.destroy());
    this.nodeLayer.removeChildren().forEach((child) => child.destroy());
    this.labelLayer.removeChildren().forEach((child) => child.destroy());
    this.views.clear(); this.adjacency.clear();
    this.minRadius=Math.min(...this.model.nodes.map(n=>n.radius));this.maxRadius=Math.max(...this.model.nodes.map(n=>n.radius));
